import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';

/// [CustomClipper] that clips the CenterButton-variant bar to a notched shape.
///
/// The notch geometry is derived verbatim from the Figma 'Subtract' SVG path
/// (node 2627-2927, viewBox `0 0 393 116`) — four cubic Béziers that produce
/// the smooth concave curve visible in the design.
///
/// The clipper reads the FAB bounding rect from [Scaffold.geometryOf] so the
/// notch is always centred on the actual floating action button, regardless of
/// screen width.  It re-clips automatically when the scaffold geometry changes
/// (e.g. on the first frame after layout when the FAB rect becomes known).
///
/// When [geometry] does not yet carry a FAB area (first frame), the path
/// renders as a simple rounded-top rectangle so the bar is never invisible.
class BTNavigationBarClipper extends CustomClipper<Path> {
  const BTNavigationBarClipper({required this.geometry})
      : super(reclip: geometry);

  final ValueListenable<ScaffoldGeometry> geometry;

  // ── Corner radius (Figma radius-md = 12 dp) ────────────────────────────
  static const double _cornerRadius = 12.0;

  // ── Notch Bézier constants extracted from Figma SVG (node 2627-2927) ──
  //
  // All values are dp offsets from cx (horizontal centre of notch).
  //
  // Left shoulder  (Bézier 1):
  //   (cx−49, 0) → CP1 (cx−42.373, 0) → CP2 (cx−37.192, 5.512) → (cx−35.08, 11.7946)
  //
  // Left arc half  (Bézier 2):
  //   (cx−35.08, 11.7946) → CP1 (cx−30.156, 26.446) → CP2 (cx−16.311, 37) → (cx, 37)
  //
  // Right half: mirror of the above.
  static const double _notchHW = 49.0;     // half-width at bar top
  static const double _notchD  = 37.0;     // deepest y (notch bottom)
  static const double _shEndX  = 35.08;    // shoulder end x-offset
  static const double _shEndY  = 11.7946;  // shoulder end y
  static const double _sh1X    = 42.373;   // shoulder CP1 x-offset
  static const double _sh2X    = 37.192;   // shoulder CP2 x-offset
  static const double _sh2Y    = 5.512;    // shoulder CP2 y
  static const double _arc1X   = 30.156;   // arc CP1 x-offset
  static const double _arc1Y   = 26.446;   // arc CP1 y
  static const double _arc2X   = 16.311;   // arc CP2 x-offset
  // arc CP2 y == _notchD (deepest point)

  @override
  Path getClip(Size size) {
    // Translate FAB screen rect to bar-local y-coordinates.
    final Rect? fabScreen = geometry.value.floatingActionButtonArea;
    final double? barTop  = geometry.value.bottomNavigationBarTop;

    // cx defaults to horizontal midpoint; overridden by actual FAB centre
    // once Scaffold has laid out the FAB.
    final double cx = (fabScreen != null && barTop != null)
        ? fabScreen.center.dx
        : size.width / 2;

    final bool hasNotch = fabScreen != null && barTop != null;

    final path = Path()
      // ── Bottom-left → up left side ──────────────────────────────────────
      ..moveTo(0, size.height)
      ..lineTo(0, _cornerRadius)
      // ── Top-left rounded corner ─────────────────────────────────────────
      ..arcToPoint(
        const Offset(_cornerRadius, 0),
        radius: const Radius.circular(_cornerRadius),
      );

    if (hasNotch) {
      path
        // ── Bar top: left edge → notch approach ─────────────────────────
        ..lineTo(cx - _notchHW, 0)
        // ── Left shoulder ───────────────────────────────────────────────
        ..cubicTo(cx - _sh1X, 0, cx - _sh2X, _sh2Y, cx - _shEndX, _shEndY)
        // ── Left arc half ───────────────────────────────────────────────
        ..cubicTo(cx - _arc1X, _arc1Y, cx - _arc2X, _notchD, cx, _notchD)
        // ── Right arc half ──────────────────────────────────────────────
        ..cubicTo(cx + _arc2X, _notchD, cx + _arc1X, _arc1Y, cx + _shEndX, _shEndY)
        // ── Right shoulder ──────────────────────────────────────────────
        ..cubicTo(cx + _sh2X, _sh2Y, cx + _sh1X, 0, cx + _notchHW, 0);
    }

    path
      // ── Bar top: notch exit → top-right corner ──────────────────────
      ..lineTo(size.width - _cornerRadius, 0)
      // ── Top-right rounded corner ────────────────────────────────────
      ..arcToPoint(
        Offset(size.width, _cornerRadius),
        radius: const Radius.circular(_cornerRadius),
      )
      // ── Right side and bottom ────────────────────────────────────────
      ..lineTo(size.width, size.height)
      ..close();

    return path;
  }

  @override
  bool shouldReclip(BTNavigationBarClipper old) => old.geometry != geometry;
}

/// Shadow-only [CustomPainter] drawn **behind** the clipped bar.
///
/// Traces the same notched silhouette as [BTNavigationBarClipper] and paints
/// two upward-facing shadows clipped to a band above the bar top so they never
/// bleed into the transparent notch cutout.
class BTNavigationBarShadowPainter extends CustomPainter {
  BTNavigationBarShadowPainter({required this.clipper})
      : super(repaint: clipper.geometry);

  final BTNavigationBarClipper clipper;

  @override
  void paint(Canvas canvas, Size size) {
    final path = clipper.getClip(size);

    // BlurStyle.normal spreads blur in all directions from the path boundary —
    // this is the Flutter equivalent of CSS `filter: drop-shadow`.  The blur
    // follows the notch curves exactly (upward shadow + notch shadow), which
    // matches the Figma design intent.
    //
    // Interior blur (inside the bar fill area) is hidden by ClipPath +
    // ColoredBox rendered on top.  The subtle blur that appears inside the
    // notch cutout is intentional — it follows the concave curve and fades
    // behind the floating FAB, matching what Figma's drop-shadow produces.
    //
    // Shadow 1: 0px -1px 1px rgba(0,0,0,0.06) — sigma 0.5
    canvas
      ..save()
      ..translate(0, -1)
      ..drawPath(
        path,
        Paint()
          ..color = const Color(0x0F000000)
          ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 0.5),
      )
      ..restore();

    // Shadow 2: 0px -6px 15px rgba(0,0,0,0.10) — sigma 7.5
    canvas
      ..save()
      ..translate(0, -6)
      ..drawPath(
        path,
        Paint()
          ..color = const Color(0x1A000000)
          ..maskFilter = const MaskFilter.blur(BlurStyle.normal, 7.5),
      )
      ..restore();
  }

  @override
  bool shouldRepaint(BTNavigationBarShadowPainter old) =>
      old.clipper != clipper;
}

