import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/molecules/navigation_menu/navigation_menu.types.dart';
import 'package:flutter/material.dart';

/// Internal one-tab-cell widget for [BTNavigationMenu].
///
/// Renders icon (24 × 24) + label (12 px / weight 500) in a column.
/// Applies [selectedColor] when active, [unselectedColor] when not.
/// Uses [ColorFiltered] for icon tinting (works for Icon() AND SvgPicture).
/// Pressed state is instant (GestureDetector + setState — no AnimatedContainer).
class BTNavigationMenuItem extends StatefulWidget {
  const BTNavigationMenuItem({
    required this.item,
    required this.isSelected,
    required this.onTap,
    required this.selectedColor,
    required this.unselectedColor,
    super.key,
  });

  final BTNavigationItem item;
  final bool isSelected;
  final VoidCallback onTap;
  final Color selectedColor;
  final Color unselectedColor;

  @override
  State<BTNavigationMenuItem> createState() => _BTNavigationMenuItemState();
}

class _BTNavigationMenuItemState extends State<BTNavigationMenuItem> {
  bool _isPressed = false;

  @override
  Widget build(BuildContext context) {
    final color =
        widget.isSelected ? widget.selectedColor : widget.unselectedColor;
    final icon = widget.isSelected
        ? (widget.item.activeIcon ?? widget.item.icon)
        : widget.item.icon;

    return Expanded(
      child: GestureDetector(
        behavior: HitTestBehavior.opaque,
        onTap: widget.onTap,
        onTapDown: (_) => setState(() => _isPressed = true),
        onTapUp: (_) => setState(() => _isPressed = false),
        onTapCancel: () => setState(() => _isPressed = false),
        child: Opacity(
          opacity: _isPressed ? 0.6 : 1.0,
          child: Padding(
            // Figma: py-8 (8 dp top + 8 dp bottom) per menu slot.
            padding: EdgeInsets.symmetric(vertical: 8.0),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                SizedBox(
                  width: 24.0,
                  height: 24.0,
                  child: ColorFiltered(
                    colorFilter: ColorFilter.mode(color, BlendMode.srcIn),
                    child: icon,
                  ),
                ),
                SizedBox(height: 4.0),
                Text(
                  widget.item.label,
                  style: TextStyle(
                    fontSize: 12.0,
                    fontWeight: FontWeight.w500,
                    color: color,
                    // Figma: fontSize 12, lineHeight 16 → height = 16/12.
                    height: 16 / 12,
                  ),
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }
}

