// NOTE: This file is no longer used by BTNavigationMenu — it has been replaced
// by BTNavigationBarClipper (navigation_bar_clipper.dart) which integrates with
// Scaffold.geometryOf() for the centerDocked FAB pattern. Kept for reference.
import 'package:flutter/material.dart';

/// [CustomPainter] that draws the centerButton variant background.
///
/// The notch shape is derived **directly from the Figma SVG 'Subtract' path**
/// (node 2627-2927, viewBox `0 0 393 116`). The four cubic Béziers below are
/// extracted verbatim from that asset — they produce the smooth concave curve
/// visible in the design without any approximation.
///
/// ## Path structure
///
/// ```
/// bar-top: cx−49 ──shoulder──> cx−35 ──arc──> cx  ──arc──> cx+35 ──shoulder──> cx+49
///                                                  ↓ 37 dp deep
/// ```
///
/// All x-values are offsets from `cx = size.width / 2`.
/// The notch centre is always at the horizontal midpoint regardless of bar width.
///
/// ### Key measurements (dp)
/// - Notch half-width at bar top: **49**
/// - Notch depth: **37**
/// - Button diameter: **56** → button centre sits exactly at bar top (y = 0)
class BTNavigationNotchedPainter extends CustomPainter {
  const BTNavigationNotchedPainter({required this.color});

  /// Fill colour for the bar background.
  final Color color;

  // ── Corner radius ──────────────────────────────────────────────────────────
  static const double _cornerRadius = 12.0;

  // ── Notch geometry — extracted from Figma SVG (Subtract, node 2627-2927) ──
  //
  // All values are absolute dp offsets from cx (not screen-width-relative).
  // Derived from: viewBox "0 0 393 116", cx = 196.5 ≈ 197.
  //
  // Left shoulder (Bézier 1):
  //   start (cx−49, 0) → CP1 (cx−42.373, 0) → CP2 (cx−37.192, 5.512)
  //   → end (cx−35.08, 11.7946)
  //
  // Left arc half (Bézier 2):
  //   start (cx−35.08, 11.7946) → CP1 (cx−30.156, 26.446)
  //   → CP2 (cx−16.311, 37) → end (cx, 37)
  //
  // Right arc half and right shoulder are the horizontal mirrors.

  static const double _notchHW  = 49.0;     // half-width at bar top
  static const double _notchD   = 37.0;     // deepest y (notch bottom)
  static const double _shEndX   = 35.08;    // shoulder end: x-offset from cx
  static const double _shEndY   = 11.7946;  // shoulder end: y
  static const double _sh1X     = 42.373;   // shoulder CP1: x-offset from cx
  static const double _sh2X     = 37.192;   // shoulder CP2: x-offset from cx
  static const double _sh2Y     = 5.512;    // shoulder CP2: y
  static const double _arc1X    = 30.156;   // arc CP1: x-offset from cx
  static const double _arc1Y    = 26.446;   // arc CP1: y
  static const double _arc2X    = 16.311;   // arc CP2: x-offset from cx
  // arc CP2 y = _notchD (deepest point)

  @override
  void paint(Canvas canvas, Size size) {
    final fillPaint = Paint()
      ..color = color
      ..style = PaintingStyle.fill;

    final cx = size.width / 2;

    final path = Path()
      // ── Bottom-left → up left side ────────────────────────────────────────
      ..moveTo(0, size.height)
      ..lineTo(0, _cornerRadius)
      // ── Top-left rounded corner ────────────────────────────────────────────
      ..arcToPoint(
        const Offset(_cornerRadius, 0),
        radius: const Radius.circular(_cornerRadius),
      )
      // ── Bar top: left edge → notch approach ───────────────────────────────
      ..lineTo(cx - _notchHW, 0)
      // ── Left shoulder (flat → downward) ────────────────────────────────────
      ..cubicTo(
        cx - _sh1X, 0,
        cx - _sh2X, _sh2Y,
        cx - _shEndX, _shEndY,
      )
      // ── Left arc half (shoulder exit → notch bottom) ──────────────────────
      ..cubicTo(
        cx - _arc1X, _arc1Y,
        cx - _arc2X, _notchD,
        cx,          _notchD,
      )
      // ── Right arc half (notch bottom → shoulder entry) ────────────────────
      ..cubicTo(
        cx + _arc2X,  _notchD,
        cx + _arc1X,  _arc1Y,
        cx + _shEndX, _shEndY,
      )
      // ── Right shoulder (downward → flat) ───────────────────────────────────
      ..cubicTo(
        cx + _sh2X, _sh2Y,
        cx + _sh1X, 0,
        cx + _notchHW, 0,
      )
      // ── Bar top: notch exit → top-right corner ────────────────────────────
      ..lineTo(size.width - _cornerRadius, 0)
      // ── Top-right rounded corner ───────────────────────────────────────────
      ..arcToPoint(
        Offset(size.width, _cornerRadius),
        radius: const Radius.circular(_cornerRadius),
      )
      // ── Right side and bottom ──────────────────────────────────────────────
      ..lineTo(size.width, size.height)
      ..close();

    // ── Shadows — drawn above the bar only (clipped to prevent bleed into notch) ──
    // Shadow 1: offset(0, −1) blurRadius 1 → sigma ≈ 0.5
    // Clipped to a band above the bar top so the blur doesn't bleed into the notch.
    canvas
      ..save()
      ..clipRect(Rect.fromLTWH(0, -12, size.width, 12))
      ..translate(0, -1)
      ..drawPath(
        path,
        Paint()
          ..color = const Color(0x10000000)
          ..maskFilter = const MaskFilter.blur(BlurStyle.outer, 0.5),
      )
      ..restore();
    // Shadow 2: offset(0, −6) blurRadius 15 → sigma ≈ 7.5
    // Wider clip to accommodate larger blur radius.
    canvas
      ..save()
      ..clipRect(Rect.fromLTWH(0, -60, size.width, 60))
      ..translate(0, -6)
      ..drawPath(
        path,
        Paint()
          ..color = const Color(0x1A000000)
          ..maskFilter = const MaskFilter.blur(BlurStyle.outer, 7.5),
      )
      ..restore();

    // ── Fill (drawn last, on top of shadows) ──────────────────────────────
    canvas.drawPath(path, fillPaint);
  }

  @override
  bool shouldRepaint(BTNavigationNotchedPainter oldDelegate) =>
      oldDelegate.color != color;
}

/// BTNavigationMenu — bottom navigation bar molecule.
///
/// Figma: node 2627-2923 (default) · node 2627-2927 (centerButton)
/// Platform: Flutter only (M-prefix frame).
library;

export 'navigation_menu.types.dart';
export 'navigation_menu.widget.dart';

// Public data types for [BTNavigationMenu].
//
// Sliced from Figma nodes 2627-2923 (default) · 2627-2927 (centerButton).
// Platform: Flutter only (M-prefix frame).
// ignore_for_file: lines_longer_than_80_chars

import 'package:flutter/material.dart';

/// Data for a single navigation tab item.
///
/// ```dart
/// BTNavigationItem(
///   icon: Icon(Icons.home_outlined),
///   activeIcon: Icon(Icons.home),
///   label: 'Home',
/// )
/// ```
class BTNavigationItem {
  const BTNavigationItem({
    required this.icon,
    required this.label,
    this.activeIcon,
  });

  /// Icon widget shown when this item is **inactive**.
  final Widget icon;

  /// Icon widget shown when this item is **active**. Falls back to [icon].
  final Widget? activeIcon;

  /// Label text shown below the icon.
  final String label;
}

/// 56 × 56 dp gradient floating button for the CenterButton variant.
///
/// Pass this as [Scaffold.floatingActionButton] together with
/// [FloatingActionButtonLocation.centerDocked] and `extendBody: true`:
///
/// ```dart
/// Scaffold(
///   extendBody: true,
///   body: MyBody(),
///   bottomNavigationBar: BTNavigationMenu(
///     items: [...],
///     currentIndex: _index,
///     onIndexChanged: (i) => setState(() => _index = i),
///     hasCenterGap: true,
///   ),
///   floatingActionButton: BTNavigationCenterButton(
///     icon: Icon(Icons.add, color: Colors.white, size: 24),
///     onTap: () => openModal(),
///   ),
///   floatingActionButtonLocation: FloatingActionButtonLocation.centerDocked,
/// )
/// ```
class BTNavigationCenterButton extends StatefulWidget {
  const BTNavigationCenterButton({
    required this.icon,
    this.onTap,
    super.key,
  });

  /// Any widget rendered inside the gradient circle (icon, SVG, image…).
  final Widget icon;

  /// Called when the button is tapped.
  final VoidCallback? onTap;

  // ── Visual constants ────────────────────────────────────────────────────

  /// Diameter of the gradient circle (matches Figma 56 dp).
  // ignore: prefer_int_literals
  static const double size = 56.0;

  static const _gradient = LinearGradient(
    begin: Alignment.topLeft,
    end: Alignment.bottomRight,
    colors: [Color(0xFF75ADFF), Color(0xFF145BC3)],
  );

  static const _shadows = [
    BoxShadow(offset: Offset(0, 1), blurRadius: 1,   color: Color(0x10000000)),
    BoxShadow(offset: Offset(0, 1), blurRadius: 1.5, color: Color(0x1A000000)),
  ];

  @override
  State<BTNavigationCenterButton> createState() =>
      _BTNavigationCenterButtonState();
}

class _BTNavigationCenterButtonState extends State<BTNavigationCenterButton> {
  bool _isPressed = false;

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: widget.onTap,
      onTapDown:   (_) => setState(() => _isPressed = true),
      onTapUp:     (_) => setState(() => _isPressed = false),
      onTapCancel: ()  => setState(() => _isPressed = false),
      child: Opacity(
        opacity: _isPressed ? 0.85 : 1.0,
        child: Container(
          width:  BTNavigationCenterButton.size,
          height: BTNavigationCenterButton.size,
          decoration: const BoxDecoration(
            shape:     BoxShape.circle,
            gradient:  BTNavigationCenterButton._gradient,
            boxShadow: BTNavigationCenterButton._shadows,
          ),
          // ignore: prefer_int_literals
          padding: const EdgeInsets.all(16),
          child: widget.icon,
        ),
      ),
    );
  }
}

