import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/molecules/navigation_menu/internal/navigation_bar_clipper.dart';
import 'package:btech_ui/src/components/molecules/navigation_menu/internal/navigation_menu_item.dart';
import 'package:btech_ui/src/components/molecules/navigation_menu/navigation_menu.types.dart';
import 'package:flutter/foundation.dart' show ValueListenable;
import 'package:flutter/material.dart';

/// Bottom navigation bar — Figma M/NavigationMenu (nodes 2627-2923, 2627-2927).
///
/// ## Default variant (tab row):
/// ```dart
/// BTNavigationMenu(
///   items: [
///     BTNavigationItem(icon: Icon(Icons.home_outlined), activeIcon: Icon(Icons.home), label: 'Home'),
///     BTNavigationItem(icon: Icon(Icons.task_outlined), activeIcon: Icon(Icons.task), label: 'Task'),
///     BTNavigationItem(icon: Icon(Icons.chat_outlined), activeIcon: Icon(Icons.chat), label: 'Chat'),
///     BTNavigationItem(icon: Icon(Icons.person_outlined), activeIcon: Icon(Icons.person), label: 'Profile'),
///   ],
///   currentIndex: 0,
///   onIndexChanged: (i) => setState(() => _index = i),
/// )
/// ```
///
/// ## CenterButton variant — inside a [Scaffold] with a center-docked FAB:
/// ```dart
/// Scaffold(
///   extendBody: true,
///   body: MyBody(),
///   bottomNavigationBar: BTNavigationMenu(
///     items: [
///       BTNavigationItem(icon: Icon(Icons.home_outlined), label: 'Home'),
///       BTNavigationItem(icon: Icon(Icons.search),        label: 'Search'),
///       BTNavigationItem(icon: Icon(Icons.chat_outlined), label: 'Chat'),
///       BTNavigationItem(icon: Icon(Icons.person_outlined), label: 'Profile'),
///     ],
///     currentIndex: 0,
///     onIndexChanged: (i) => setState(() => _index = i),
///     hasCenterGap: true,
///   ),
///   floatingActionButton: BTNavigationCenterButton(
///     icon: Icon(Icons.add, color: Colors.white),
///     onTap: () => openModal(),
///   ),
///   floatingActionButtonLocation: FloatingActionButtonLocation.centerDocked,
/// )
/// ```
class BTNavigationMenu extends StatefulWidget {
  /// Creates a navigation menu.
  ///
  /// Set [hasCenterGap] to `true` for the CenterButton variant. In that case:
  /// - [items] must have an **even** count (2 or 4).
  /// - The widget must be placed inside a [Scaffold] with
  ///   `floatingActionButton: BTNavigationCenterButton(...)`,
  ///   `floatingActionButtonLocation: FloatingActionButtonLocation.centerDocked`,
  ///   and `extendBody: true`.
  const BTNavigationMenu({
    required this.items,
    required this.currentIndex,
    this.onIndexChanged,
    this.hasCenterGap = false,
    this.selectedColor,
    this.unselectedColor,
    super.key,
  }) : assert(
         !hasCenterGap || items.length % 2 == 0,
         'hasCenterGap requires an even number of items (2 or 4)',
       );

  /// Navigation items.
  ///
  /// Default variant: 2–5 items.
  /// CenterButton variant: 2 or 4 items (even count required).
  final List<BTNavigationItem> items;

  /// Zero-based index of the currently active item.
  ///
  /// The center FAB is NOT counted — only tab items use this index.
  final int currentIndex;

  /// Called with the new index when a tab item is tapped.
  final ValueChanged<int>? onIndexChanged;

  /// When `true`, activates the CenterButton variant.
  ///
  /// Leaves a gap in the item row for the [FloatingActionButton] and clips
  /// the bar to a notched shape by reading [Scaffold.geometryOf].
  final bool hasCenterGap;

  /// Active icon / label colour. Defaults to `context.btColor.brand.primary`.
  final Color? selectedColor;

  /// Inactive icon / label colour. Defaults to `context.btColor.text.secondary`.
  final Color? unselectedColor;

  // ── Visual constants ─────────────────────────────────────────────────────

  /// Top-left / top-right corner radius (radius-md = 12 dp).
  static const double _cornerRadius = 12.0;

  /// Bottom padding covering iOS home indicator / Android gesture bar.
  static const double _bottomPadding = 28.0;

  /// Invisible spacer width in the item row for the center gap.
  static const double _notchSpacerWidth = 72.0;

  // Shared box-shadow values used by both variants.
  // Default variant: applied via BoxDecoration.boxShadow (rectangular bar).
  // CenterButton variant: replicated by BTNavigationBarShadowPainter (notched).
  // Figma: 0px -1px 1px rgba(0,0,0,0.06), 0px -6px 15px rgba(0,0,0,0.10)
  // 0x0F = 15/255 ≈ 6 %, 0x1A = 26/255 ≈ 10 %
  static const List<BoxShadow> _barShadows = [
    BoxShadow(offset: Offset(0, -1), blurRadius: 1,  color: Color(0x0F000000)),
    BoxShadow(offset: Offset(0, -6), blurRadius: 15, color: Color(0x1A000000)),
  ];

  @override
  State<BTNavigationMenu> createState() => _BTNavigationMenuState();
}

class _BTNavigationMenuState extends State<BTNavigationMenu> {
  /// Scaffold geometry listenable — only set when [hasCenterGap] is true.
  ///
  /// Nullable so that [didChangeDependencies] (which is called on every
  /// dependency change, e.g. theme switch) cannot trigger a second
  /// initialisation and throw [LateInitializationError].
  ValueListenable<ScaffoldGeometry>? _geometryListenable;

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    if (widget.hasCenterGap && _geometryListenable == null) {
      _geometryListenable = Scaffold.geometryOf(context);
    }
  }

  @override
  Widget build(BuildContext context) {
    final colors          = context.btColor;
    final selectedColor   = widget.selectedColor   ?? colors.brand.primary;
    final unselectedColor = widget.unselectedColor ?? colors.text.secondary;

    return widget.hasCenterGap
        ? _buildCenterButtonVariant(context, selectedColor, unselectedColor)
        : _buildDefaultVariant(context, selectedColor, unselectedColor);
  }

  // ── Default variant ──────────────────────────────────────────────────────

  Widget _buildDefaultVariant(
    BuildContext context,
    Color selected,
    Color unselected,
  ) {
    final colors = context.btColor;
    return DecoratedBox(
      decoration: BoxDecoration(
        color: colors.bg.primary,
        borderRadius: const BorderRadius.vertical(
          top: Radius.circular(BTNavigationMenu._cornerRadius),
        ),
        boxShadow: BTNavigationMenu._barShadows,
      ),
      child: Padding(
        padding: const EdgeInsets.fromLTRB(16, 8, 16, BTNavigationMenu._bottomPadding),
        child: Row(
          children: [
            for (var i = 0; i < widget.items.length; i++)
              BTNavigationMenuItem(
                item: widget.items[i],
                isSelected: i == widget.currentIndex,
                onTap: () => widget.onIndexChanged?.call(i),
                selectedColor: selected,
                unselectedColor: unselected,
              ),
          ],
        ),
      ),
    );
  }

  // ── CenterButton variant ─────────────────────────────────────────────────

  Widget _buildCenterButtonVariant(
    BuildContext context,
    Color selected,
    Color unselected,
  ) {
    final colors     = context.btColor;
    final barBg      = colors.bg.primary;
    final half       = widget.items.length ~/ 2;
    final leftItems  = widget.items.sublist(0, half);
    final rightItems = widget.items.sublist(half);

    final clipper = BTNavigationBarClipper(geometry: _geometryListenable!);

    // CustomPaint (behind) draws the two upward-facing Figma shadows using
    // BlurStyle.outer — blur is restricted to OUTSIDE the notched path so it
    // never appears inside the transparent notch cutout.
    //
    // ClipPath + ColoredBox (in front) fill the notched shape with the bar
    // background, covering any downward blur that fell inside the bar area.
    //
    // Note: PhysicalShape.elevation was avoided here because it produces a
    // downward Material elevation shadow, which is off-screen for a bar at the
    // bottom of the display (the shadow goes below the bar, not above it).
    final barContent = Padding(
      padding: const EdgeInsets.fromLTRB(16, 8, 16, BTNavigationMenu._bottomPadding),
      child: Row(
        children: [
          // Left half of items.
          for (var i = 0; i < leftItems.length; i++)
            BTNavigationMenuItem(
              item: leftItems[i],
              isSelected: i == widget.currentIndex,
              onTap: () => widget.onIndexChanged?.call(i),
              selectedColor: selected,
              unselectedColor: unselected,
            ),
          // Invisible gap where the FAB sits.
          const SizedBox(width: BTNavigationMenu._notchSpacerWidth),
          // Right half (index offset by leftItems.length).
          for (var i = 0; i < rightItems.length; i++)
            BTNavigationMenuItem(
              item: rightItems[i],
              isSelected: (i + leftItems.length) == widget.currentIndex,
              onTap: () => widget.onIndexChanged?.call(i + leftItems.length),
              selectedColor: selected,
              unselectedColor: unselected,
            ),
        ],
      ),
    );

    return CustomPaint(
      painter: BTNavigationBarShadowPainter(clipper: clipper),
      child: ClipPath(
        clipper: clipper,
        child: ColoredBox(color: barBg, child: barContent),
      ),
    );
  }
}
